import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Excluder;
import com.google.gson.Gson;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonExcluderTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void testExcluder_notNull() throws Exception {
    Excluder excluder = gson.excluder();
    assertNotNull(excluder, "Excluder should not be null");
  }

  @Test
  public void testExcluder_reflectionAccess() throws Exception {
    // Access private final field 'excluder' via reflection and compare to method result
    Field excluderField = Gson.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    Excluder fieldValue = (Excluder) excluderField.get(gson);

    Excluder methodValue = gson.excluder();

    assertSame(fieldValue, methodValue, "excluder() should return the same instance as the private field");
  }
}
